// Flatten both trend sources into a single readable list for the AI agents
const items = $input.all();
const videos = [];

for (const item of items) {
  if (item.json.items) {
    for (const video of item.json.items) {
      videos.push(
        `TITLE: ${video.snippet.title} | VIEWS: ${video.statistics.viewCount} | CHANNEL: ${video.snippet.channelTitle}`
      );
    }
  }
}

return [{ json: { videoList: videos.join('\n') } }];

